            border-color: var(--gold);
            box-shadow: 0 6px 30px rgba(212, 175, 55, 0.2);
        }

        .player-main {
            display: flex;
            align-items: center;
            gap: 12px;
        }

        .play-btn {
            width: 50px;
            height: 50px;
            background: linear-gradient(135deg, var(--gold) 0%, var(--gold-light) 100%);
            border: none;
            border-radius: 50%;
            color: var(--navy);
            font-size: 1.2rem;
            cursor: pointer;
