            width: 60px;
            height: 4px;
            background: rgba(212, 175, 55, 0.2);
            border-radius: 2px;
            cursor: pointer;
            position: relative;
        }

        .volume-fill {
            height: 100%;
            background: var(--gold);
            border-radius: 2px;
            width: 70%;
        }

        .player-expanded {
            display: none;
            width: 100%;
            margin-top: 10px;
            padding-top: 10px;
            border-top: 1px solid rgba(212, 175, 55, 0.2);
        }

        .music-player.expanded {
            border-radius: 20px;
            flex-wrap: wrap;
        }

        .music-player.expanded .player-expanded {
            display: flex;
            flex-direction: column;
            gap: 8px;
        }

        .expand-btn {
            background: none;
            border: none;
            color: var(--gold);
            font-size: 0.8rem;
            cursor: pointer;
            padding: 4px;
            transition: transform 0.3s;
        }

        .music-player.expanded .expand-btn {
            transform: rotate(180deg);
        }

        .error-message {
            position: fixed;
            bottom: 100px;
            left: 20px;
            background: rgba(231, 76, 60, 0.9);
            color: white;
            padding: 12px 20px;
            border-radius: 8px;
            font-size: 0.85rem;
            z-index: 10000;
            display: none;
            animation: slideIn 0.3s ease;
        }

        .error-message.show {
            display: block;
        }

        @keyframes slideIn {
            from {
                opacity: 0;
                transform: translateY(20px);
            }
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        /* Loading spinner */
        .spinner {
            width: 20px;
            height: 20px;
            border: 2px solid rgba(212, 175, 55, 0.3);
            border-top-color: var(--gold);
            border-radius: 50%;
            animation: spin 1s linear infinite;
        }

        @keyframes spin {
            to { transform: rotate(360deg); }
        }

        /* Hidden SoundCloud iframe */
        #scWidget {
            position: absolute;
            width: 0;
            height: 0;
            border: none;
            opacity: 0;
            pointer-events: none;
            overflow: hidden;
        }

        /* ElevenLabs Widget */
