            position: fixed;
            bottom: 100px;
            right: 20px;
            z-index: 9998;
        }

        /* Responsive */
        @media (max-width: 768px) {
            .nav-links {
                display: none;
            }

            .mobile-menu-btn {
                display: block;
            }

            .hero h1 {
                font-size: 2.5rem;
            }

            .floating-cards {
                display: none;
            }

            .contact-grid {
                gap: 2rem;
            }

            .music-player {
                left: 10px;
                bottom: 10px;
                max-width: calc(100vw - 20px);
                padding: 10px 12px;
            }

            .play-btn {
                width: 45px;
                height: 45px;
                font-size: 1rem;
            }

            .player-info {
                max-width: 120px;
            }

            .portrait-frame {
                width: 220px;
                height: 220px;
            }

            .portrait-name {
                font-size: 2rem;
            }

            elevenlabs-convai {
                bottom: 80px;
                right: 10px;
            }
        }

        /* Scroll Animation */
        .fade-in {
            opacity: 0;
            transform: translateY(30px);
            transition: all 0.8s;
        }

        .fade-in.visible {
            opacity: 1;
            transform: translateY(0);
        }

        /* Loading state */
        .loading-overlay {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: var(--navy);
            z-index: 99999;
            display: flex;
            justify-content: center;
            align-items: center;
            transition: opacity 0.5s, visibility 0.5s;
        }

        .loading-overlay.hidden {
            opacity: 0;
            visibility: hidden;
        }

        .loader {
            text-align: center;
        }

        .loader-text {
            font-family: 'Playfair Display', serif;
            font-size: 1.5rem;
            color: var(--gold);
            margin-bottom: 1rem;
        }

        .loader-bar {
            width: 200px;
            height: 2px;
            background: rgba(212, 175, 55, 0.2);
            border-radius: 1px;
            overflow: hidden;
            margin: 0 auto;
        }

        .loader-progress {
            height: 100%;
            background: var(--gold);
            width: 0%;
            animation: loading 1.5s ease-in-out forwards;
        }

        @keyframes loading {
            0% { width: 0%; }
            100% { width: 100%; }
        }
    </style>
</head>
